const validateUserId = (id) => {
  const parsed = parseInt(id, 10);
  if (isNaN(parsed) || parsed <= 0) {
    throw new Error('Invalid user ID: must be a positive integer');
  }
  return parsed;
};

/**
 * Sanitize user data before sending
 */
const sanitizeUser = (user) => {
  return {
    id: user.id,
    name: validator.escape(user.name),
    // Don't expose email without proper authorization
  };
};

// ===== ROUTES =====

/**
 * Health check endpoint
 */
app.get('/health', (req, res) => {
  try {
    res.json({
      status: 'ok',
      timestamp: new Date().toISOString(),
      uptime: process.uptime(),
    });
  } catch (error) {
    res.status(500).json({ error: 'Health check failed' });
  }
});

/**
 * Get users endpoint with validation
 * NOTE: In production, add authentication middleware
 */
app.get('/users', (req, res, next) => {
  try {
    // Validate query parameters
    const { id } = req.query;

    const mockUsers = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // If specific user ID requested, validate it
    if (id !== undefined) {
      const userId = validateUserId(id);
      const user = mockUsers.find(u => u.id === userId);

      if (!user) {
        return res.status(404).json({ error: 'User not found' });
      }

      return res.json(sanitizeUser(user));
    }

    // Return sanitized user list (without sensitive emails)
    const sanitizedUsers = mockUsers.map(user => ({
      id: user.id,
      name: validator.escape(user.name),
    }));

    res.json(sanitizedUsers);
  } catch (error) {
    next(error); // Pass to error handler
  }
});

// ===== 404 HANDLER =====

app.use((req, res) => {
  res.status(404).json({
    error: 'Not found',
    path: req.path,
  });
});

// ===== ERROR HANDLING MIDDLEWARE =====
